CustomField.formula:
IF(INCLUDES(Statut__c, "Terminé"), "✅ Projet clôturé",

/* --- 1. ALERTE BUDGET --- */
IF(actual_cost__c > budget_c__c, "🔴 Budget Dépassé; ", 
    IF(actual_cost__c > (budget_c__c * 0.9), "🟠 Seuil 90%; ", "")
) & 

/* --- 2. ALERTE CALENDRIER --- */
IF(AND(INCLUDES(Statut__c, "En cours"), (endDate__c - TODAY()) < 0), "🚨 Échéance Passée; ", 
    IF(AND(INCLUDES(Statut__c, "En cours"), (endDate__c - TODAY()) <= 3), "⚠️ Fin Proche; ", "")
) &

/* --- 3. ALERTE AVANCEMENT --- */
IF(AND(NOT(INCLUDES(Statut__c, "Terminé")), progression_pourcentage__c < 0.2), "📉 Faible Avancement; ", "") &

/* --- 4. MESSAGE SI TOUT EST OK --- */
IF(AND(
    actual_cost__c <= budget_c__c, 
    OR(NOT(INCLUDES(Statut__c, "En cours")), (endDate__c - TODAY()) > 3),
    progression_pourcentage__c >= 0.2
), "🟢 Tout est OK", "")

)
